import * as express_serve_static_core from 'express-serve-static-core';

/**
 * OAuth broker — handles PKCE and token exchange server-side.
 *
 * Two operation modes:
 *   Managed  – set GOOGLE_CLIENT_ID + GOOGLE_CLIENT_SECRET env vars
 *   BYOK     – caller passes client_id + client_secret as query params
 *
 * Two delivery modes:
 *   web_message (default) – popup postMessages tokens back to opener
 *   redirect              – redirects to original URI with tokens in URL hash
 */
declare const app: express_serve_static_core.Express;

export { app as default };
